// @ts-check
/** @typedef {import('../../InvocationContext.js').InvocationContext} InvocationContext */

import { Command } from '../../../utils/Command.js'
import { CommandType } from '../../../utils/CommandType.js'
import { RuntimeName } from '../../../utils/RuntimeName.js'
import { handleResultWithAction } from './TypeParsingUtils.js'

/**
 * @param {InvocationContext} invocationContext
 * @returns {Date}
 */
export function parseDate(invocationContext) {
    const result = invocationContext.invokeInstanceMethod('getTime').execute()
    return handleResultWithAction(result, (/** @type {any} */ timestamp) => {
        if (timestamp == null) throw new Error('getTime returned null')
        return new Date(Number(timestamp))
    })
}

/**
 * Inbound: Node.js result type string → JavaScript object
 * @type {Map<string, (invocationContext: InvocationContext) => unknown>}
 */
export const NodejsTypeParsingFunctions = new Map([
    ['Date', parseDate],
])

/**
 * Outbound: JavaScript object → Command graph targeting the Node.js runtime
 * @type {Map<Function, (value: any) => Command>}
 */
export const NodejsParsingArgument = new Map([
    [Date, (/** @type {Date} */ value) => new Command(RuntimeName.Nodejs, CommandType.CreateClassInstance, [
        new Command(RuntimeName.Nodejs, CommandType.GetType, ['Date']),
        value.getTime(),
    ])],
])
